def get_oneroot(p, e):
    while True:
        Zp = Zmod(p)                     # 在模 p 的有限域上
        g = Zp.random_element()          # 随机取一个元素
        g = g^((p-1) // e)               # 提升为 e 次单位根：g^e = 1

        # 检查是否是“本原 e 次单位根”（阶正好是 e）
        for mult in divisors(e):         
            if (mult != e):              # 检查所有真因子
                g2 = g^mult
                if (g2 == 1):            # 如果存在更小幂等于1，说明阶不够
                    break
        else:
            return g                     # 找到阶正好为 e 的元素

def decrypt(p, c, e):
    w = gcd(e, p-1)                     # w = gcd(e, p-1)，决定解的个数
    e1, p1 = e // w, (p-1) // w         # 把 e 和 p-1 分解
    d = inverse_mod(e1, p1)             # 求 e1 在模 p1 下的逆元
    c1 = pow(c, d, p)                   # 相当于“降幂”，得到一个中间值
    g, a, b = xgcd(p1, w)               # 扩展欧几里得：a*p1 + b*w = 1
    g = get_oneroot(p, w)               # 找一个 w 次单位根（生成所有解用）
    m = pow(c1, b, p)                   # 构造一个特解 m
    # 所有解 = m * g^i（i = 0...w-1）
    return [ZZ(m * g^i) for i in range(w)]


# 在模 p 下求所有解
